import io.grpc.*;
import io.grpc.stub.StreamObserver;
import java.io.*;
import java.nio.file.*;
import java.security.SecureRandom;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Logger;

public class SecureFileTransferService extends FileTransferGrpc.FileTransferImplBase {
    private static final Logger logger = Logger.getLogger(SecureFileTransferService.class.getName());
    private static final int MAX_MESSAGE_SIZE = 100 * 1024 * 1024; // 100MB
    private static final int CHUNK_SIZE = 1024 * 1024; // 1MB
    private final ConcurrentHashMap<String, FileTransferContext> activeTransfers = new ConcurrentHashMap<>();
    private final AtomicLong transferCounter = new AtomicLong(0);
    private final SecureRandom random = new SecureRandom();

    @Override
    public StreamObserver<UploadRequest> uploadFile(StreamObserver<UploadResponse> responseObserver) {
        return new StreamObserver<UploadRequest>() {
            private String transferId;
            private File tempFile;
            private FileOutputStream fileOutputStream;
            private long totalBytes = 0;
            private long startTime = System.currentTimeMillis();

            @Override
            public void onNext(UploadRequest request) {
                try {
                    if (transferId == null) {
                        transferId = generateTransferId();
                        tempFile = createTempFile(transferId);
                        fileOutputStream = new FileOutputStream(tempFile);
                        activeTransfers.put(transferId, new FileTransferContext(transferId, tempFile));
                    }

                    if (request.hasMetadata()) {
                        validateMetadata(request.getMetadata());
                    }

                    if (request.hasData()) {
                        byte[] data = request.getData().toByteArray();
                        totalBytes += data.length;
                        fileOutputStream.write(data);
                    }

                    if (request.hasComplete() && request.getComplete()) {
                        completeUpload();
                        responseObserver.onNext(UploadResponse.newBuilder()
                                .setTransferId(transferId)
                                .setTotalBytes(totalBytes)
                                .setDuration(System.currentTimeMillis() - startTime)
                                .build());
                        responseObserver.onCompleted();
                    }
                } catch (Exception e) {
                    logger.severe("Upload error: " + e.getMessage());
                    try {
                        fileOutputStream.close();
                        Files.deleteIfExists(tempFile.toPath());
                    } catch (IOException ignored) {}
                    responseObserver.onError(Status.INTERNAL.withDescription("Upload failed").withCause(e).asException());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.severe("Upload stream error: " + t.getMessage());
                try {
                    if (fileOutputStream != null) {
                        fileOutputStream.close();
                    }
                    if (tempFile != null && Files.exists(tempFile.toPath())) {
                        Files.deleteIfExists(tempFile.toPath());
                    }
                } catch (IOException ignored) {}
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                if (transferId != null) {
                    activeTransfers.remove(transferId);
                }
            }

            private void completeUpload() throws IOException {
                fileOutputStream.flush();
                fileOutputStream.close();
                activeTransfers.remove(transferId);
            }
        };
    }

    @Override
    public StreamObserver<DownloadRequest> downloadFile(StreamObserver<DownloadResponse> responseObserver) {
        return new StreamObserver<DownloadRequest>() {
            private String transferId;
            private FileInputStream fileInputStream;
            private long totalBytes = 0;

            @Override
            public void onNext(DownloadRequest request) {
                try {
                    if (transferId == null) {
                        transferId = request.getTransferId();
                        FileTransferContext context = activeTransfers.get(transferId);
                        if (context == null) {
                            responseObserver.onError(Status.NOT_FOUND.withDescription("Transfer not found").asException());
                            return;
                        }
                        fileInputStream = new FileInputStream(context.tempFile);
                    }

                    byte[] buffer = new byte[CHUNK_SIZE];
                    int bytesRead = fileInputStream.read(buffer);
                    if (bytesRead > 0) {
                        totalBytes += bytesRead;
                        responseObserver.onNext(DownloadResponse.newBuilder()
                                .setData(com.google.protobuf.ByteString.copyFrom(buffer, 0, bytesRead))
                                .build());
                    } else {
                        fileInputStream.close();
                        responseObserver.onCompleted();
                    }
                } catch (Exception e) {
                    logger.severe("Download error: " + e.getMessage());
                    try {
                        if (fileInputStream != null) {
                            fileInputStream.close();
                        }
                    } catch (IOException ignored) {}
                    responseObserver.onError(Status.INTERNAL.withDescription("Download failed").withCause(e).asException());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.severe("Download stream error: " + t.getMessage());
                try {
                    if (fileInputStream != null) {
                        fileInputStream.close();
                    }
                } catch (IOException ignored) {}
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                if (transferId != null) {
                    activeTransfers.remove(transferId);
                }
            }
        };
    }

    @Override
    public void transferData(TransferRequest request, StreamObserver<TransferResponse> responseObserver) {
        try {
            String transferId = generateTransferId();
            File tempFile = createTempFile(transferId);
            FileTransferContext context = new FileTransferContext(transferId, tempFile);
            activeTransfers.put(transferId, context);

            // Process data in chunks
            byte[] data = request.getData().toByteArray();
            long totalBytes = data.length;
            long startTime = System.currentTimeMillis();

            // Simulate processing
            Thread.sleep(100);

            responseObserver.onNext(TransferResponse.newBuilder()
                    .setTransferId(transferId)
                    .setTotalBytes(totalBytes)
                    .setProcessingTime(System.currentTimeMillis() - startTime)
                    .build());
            responseObserver.onCompleted();
        } catch (Exception e) {
            logger.severe("Data transfer error: " + e.getMessage());
            responseObserver.onError(Status.INTERNAL.withDescription("Data transfer failed").withCause(e).asException());
        }
    }

    private void validateMetadata(UploadMetadata metadata) {
        if (metadata.getFileName().isEmpty()) {
            throw new IllegalArgumentException("File name cannot be empty");
        }
        if (metadata.getFileName().length() > 255) {
            throw new IllegalArgumentException("File name too long");
        }
        if (metadata.getContentType().length() > 100) {
            throw new IllegalArgumentException("Content type too long");
        }
        if (metadata.getTimestamp() < 0) {
            throw new IllegalArgumentException("Invalid timestamp");
        }
    }

    private String generateTransferId() {
        return "transfer_" + transferCounter.incrementAndGet() + "_" + random.nextLong();
    }

    private File createTempFile(String transferId) throws IOException {
        return File.createTempFile("upload_" + transferId + "_", ".tmp");
    }

    private static class FileTransferContext {
        final String transferId;
        final File tempFile;

        FileTransferContext(String transferId, File tempFile) {
            this.transferId = transferId;
            this.tempFile = tempFile;
        }
    }

    public static void main(String[] args) throws Exception {
        Server server = ServerBuilder.forPort(8080)
                .addService(new SecureFileTransferService())
                .maxInboundMessageSize(MAX_MESSAGE_SIZE)
                .build()
                .start();
        logger.info("Server started on port " + server.getPort());
        server.blockUntilShutdown();
    }
}